var sdk = window.CueStack;
function updateLabel(el) { document.getElementById(el.id + '_val').textContent = el.value + (el.id === 'waste' ? '%' : ''); }
function log(msg) { var el = document.getElementById('log'); el.textContent += msg + '\n'; el.scrollTop = el.scrollHeight; }

async function generateData() {
  var btn = document.getElementById('genBtn');
  btn.disabled = true;
  document.getElementById('status').textContent = 'Generating...';
  document.getElementById('log').textContent = '';

  var Te = parseInt(document.getElementById('te').value);
  var sp = parseInt(document.getElementById('sp').value);
  var days = parseInt(document.getElementById('days').value);
  var waste = parseInt(document.getElementById('waste').value) / 100;
  var startH = parseInt(document.getElementById('start_h').value);
  var endH = parseInt(document.getElementById('end_h').value);

  log('AC Power Simulator');
  log('Te=' + Te + '\u00b0C, Setpoint=' + sp + '\u00b0C, Days=' + days + ', Waste=' + (waste*100) + '%');
  log('Schedule: ' + startH + ':00 - ' + endH + ':00');
  log('');

  var rows = [];
  var now = Date.now();
  var baseDate = now - days * 24 * 3600 * 1000;

  for (var d = 0; d < days; d++) {
    var dayStart = baseDate + d * 24 * 3600 * 1000;
    var dayTe = Te + (Math.random() - 0.5) * 4;
    var dayWaste = waste + (Math.random() - 0.5) * 0.15;

    for (var h = 0; h < 24; h++) {
      for (var m = 0; m < 60; m += 15) {
        var ts = new Date(dayStart + h * 3600000 + m * 60000);
        var hf = h + m / 60;
        var teNow = dayTe + Math.sin(hf / 24 * Math.PI * 2 - 1) * 2;
        var power, ti, state;

        if (hf < startH || hf >= endH) {
          state = 'OFF';
          power = 5 + Math.random() * 10;
          var offH = hf < startH ? (hf + 24 - endH) : (hf - endH);
          ti = teNow - (teNow - sp) * Math.exp(-0.3 * offH);
        } else if (hf < startH + 2) {
          state = 'PULLDOWN';
          var prog = (hf - startH) / 2;
          power = (800 + (1 - prog) * 600) * dayWaste + Math.random() * 100;
          ti = (teNow - 2) - prog * (teNow - 2 - sp);
        } else {
          state = 'CYCLING';
          var cycBase = (48 * Math.max(teNow - sp, 0) + 98) * dayWaste;
          power = cycBase + (Math.random() - 0.5) * 80;
          ti = sp + (Math.random() - 0.5) * 0.8;
        }

        rows.push({
          timestamp: ts.toISOString(),
          power_w: Math.max(0, +power.toFixed(1)),
          temp_int: +(ti + (Math.random() - 0.5) * 0.3).toFixed(2),
          temp_ext: +(teNow + (Math.random() - 0.5) * 0.5).toFixed(2),
          state: state
        });
      }
    }
    log('Day ' + (d+1) + ': ' + 96 + ' readings (Te=' + dayTe.toFixed(1) + '\u00b0C)');
  }

  log('');
  log('Total: ' + rows.length + ' readings');
  log('Inserting into power_consumption table...');

  // Insert via SDK in batches
  var inserted = 0;
  var batchSize = 50;
  for (var i = 0; i < rows.length; i += batchSize) {
    var batch = rows.slice(i, i + batchSize);
    try {
      await sdk.insert('power_consumption', batch);
      inserted += batch.length;
      if (i % 200 === 0) log('  ' + inserted + ' / ' + rows.length);
    } catch(e) {
      log('Error: ' + e.message);
      break;
    }
  }

  log('');
  log('\u2705 Inserted ' + inserted + ' rows into power_consumption');
  log('Run the Energy Model Training notebook to train models on this data.');

  document.getElementById('status').textContent = 'Done: ' + inserted + ' rows';
  btn.disabled = false;
}

async function clearData() {
  if (!confirm('Delete all rows from power_consumption?')) return;
  log('Clearing power_consumption table...');
  // Note: SDK doesn't have delete-all, but we can log the intent
  log('Use the database page to clear the table, or re-seed.');
}
